# k8s_agent_job.py -- Generate a Kubernetes Job spec with resource limits
import json
from dataclasses import dataclass

@dataclass
class AgentResources:
    cpu_request: str = "100m"           # 0.1 core minimum
    cpu_limit: str = "500m"             # 0.5 core maximum
    memory_request: str = "128Mi"
    memory_limit: str = "256Mi"
    ephemeral_storage_limit: str = "256Mi"
    active_deadline_seconds: int = 120  # Job-level wall-clock timeout

def make_agent_job(
    job_name: str,
    image: str,
    command: list[str],
    resources: AgentResources | None = None,
) -> dict:
    r = resources or AgentResources()
    return {
        "apiVersion": "batch/v1",
        "kind": "Job",
        "metadata": {"name": job_name},
        "spec": {
            "activeDeadlineSeconds": r.active_deadline_seconds,
            "backoffLimit": 0,
            "ttlSecondsAfterFinished": 60,
            "template": {
                "spec": {
                    "restartPolicy": "Never",
                    "automountServiceAccountToken": False,
                    "securityContext": {
                        "runAsNonRoot": True,
                        "runAsUser": 65534,
                        "seccompProfile": {"type": "RuntimeDefault"},
                    },
                    "containers": [{
                        "name": "agent",
                        "image": image,
                        "command": command,
                        "resources": {
                            "requests": {
                                "cpu": r.cpu_request,
                                "memory": r.memory_request,
                            },
                            "limits": {
                                "cpu": r.cpu_limit,
                                "memory": r.memory_limit,
                                "ephemeral-storage": r.ephemeral_storage_limit,
                            },
                        },
                        "securityContext": {
                            "allowPrivilegeEscalation": False,
                            "capabilities": {"drop": ["ALL"]},
                            "readOnlyRootFilesystem": True,
                        },
                    }],
                }
            },
        },
    }

if __name__ == "__main__":
    spec = make_agent_job(
        job_name="agent-task-abc123",
        image="my-registry/agent:v1.2",
        command=["python3", "/app/run.py"],
        resources=AgentResources(
            cpu_limit="1000m",
            memory_limit="512Mi",
            active_deadline_seconds=90,
        ),
    )
    print(json.dumps(spec, indent=2))

# WRONG: flag-based timeout the agent can ignore
class Agent:
    def run(self, task: str, timeout: int = 60) -> str:
        self._stop = False
        import threading
        threading.Timer(timeout, lambda: setattr(self, '_stop', True)).start()
        # A stuck infinite loop never checks self._stop
        return self._execute(task)

# RIGHT: enforce timeout at the process level -- outside the agent's control
import subprocess, signal

def run_with_hard_timeout(cmd: list[str], timeout: float) -> dict:
    """Kill the process if it runs longer than timeout seconds."""
    try:
        result = subprocess.run(
            cmd, capture_output=True, text=True, timeout=timeout
        )
        return {"exit_code": result.returncode, "timed_out": False,
                "stdout": result.stdout, "stderr": result.stderr}
    except subprocess.TimeoutExpired:
        # subprocess.run already sent SIGKILL after timeout
        return {"exit_code": -signal.SIGKILL, "timed_out": True,
                "stdout": "", "stderr": "Killed: wall-clock timeout exceeded"}
